
registerApp('paint', function(){
  const wrap=document.createElement('div'); wrap.style.height='100%'; wrap.style.display='flex'; wrap.style.flexDirection='column';
  const tb=document.createElement('div'); tb.className='toolbar';
  const sel=document.createElement('select'); ['Pencil','Eraser','Eyedropper'].forEach((t,i)=>{ const o=document.createElement('option'); o.value=t.toLowerCase(); o.textContent=t; sel.append(o); });
  const size=document.createElement('input'); size.type='range'; size.min=1; size.max=24; size.value=4;
  const color=document.createElement('input'); color.type='color'; color.value='#000000';
  const bUndo=document.createElement('button'); bUndo.textContent='Undo'; const bRedo=document.createElement('button'); bRedo.textContent='Redo';
  const bClear=document.createElement('button'); bClear.textContent='Clear'; const bImp=document.createElement('button'); bImp.textContent='Import'; const bExp=document.createElement('button'); bExp.textContent='Export PNG';
  tb.append(sel,size,color,bUndo,bRedo,bClear,bImp,bExp);
  const canvas=document.createElement('canvas'); canvas.style.flex='1'; canvas.style.background='#fff';
  wrap.append(tb, canvas);
  const w=createWindow({title:'Paint', content:wrap, appId:'paint', width:820, height:560});
  const ctx=canvas.getContext('2d'); let dpr=window.devicePixelRatio||1; function resize(){ const r=canvas.getBoundingClientRect(); canvas.width=Math.floor(r.width*dpr); canvas.height=Math.floor((w.clientHeight-80)*dpr); ctx.scale(dpr,dpr);} setTimeout(resize,50); window.addEventListener('resize', resize);
  let drawing=false, last=null, tool='pencil', hist=[], redo=[];
  function push(){ hist.push(canvas.toDataURL()); if(hist.length>40) hist.shift(); redo.length=0; }
  canvas.addEventListener('pointerdown',e=>{ drawing=true; last=[e.offsetX,e.offsetY]; push(); if(sel.value==='eyedropper'){ const d=ctx.getImageData(e.offsetX,e.offsetY,1,1).data; color.value='#'+[d[0],d[1],d[2]].map(x=>x.toString(16).padStart(2,'0')).join(''); } });
  canvas.addEventListener('pointermove',e=>{ if(!drawing) return; if(sel.value==='eraser'){ ctx.clearRect(e.offsetX-+size.value/2,e.offsetY-+size.value/2,+size.value,+size.value); } else if(sel.value==='pencil'){ ctx.strokeStyle=color.value; ctx.lineWidth=+size.value; ctx.lineCap='round'; ctx.beginPath(); ctx.moveTo(last[0], last[1]); ctx.lineTo(e.offsetX,e.offsetY); ctx.stroke(); last=[e.offsetX,e.offsetY]; } });
  window.addEventListener('pointerup',()=> drawing=false);
  bUndo.onclick=()=>{ if(!hist.length) return; const u=hist.pop(); redo.push(canvas.toDataURL()); const img=new Image(); img.onload=()=>{ ctx.clearRect(0,0,canvas.width,canvas.height); ctx.drawImage(img,0,0); }; img.src=u; };
  bRedo.onclick=()=>{ if(!redo.length) return; const u=redo.pop(); hist.push(canvas.toDataURL()); const img=new Image(); img.onload=()=>{ ctx.clearRect(0,0,canvas.width,canvas.height); ctx.drawImage(img,0,0); }; img.src=u; };
  bClear.onclick=()=>{ ctx.clearRect(0,0,canvas.width,canvas.height); };
  bImp.onclick=()=>{ const inp=document.createElement('input'); inp.type='file'; inp.accept='image/*'; inp.onchange=()=>{ const f=inp.files[0]; const img=new Image(); img.onload=()=>{ ctx.drawImage(img,0,0); }; img.src=URL.createObjectURL(f); }; inp.click(); };
  bExp.onclick=()=>{ const a=document.createElement('a'); a.href=canvas.toDataURL('image/png'); a.download='paint.png'; a.click(); };

  /* PAINT_SESSION_TOKEN_V1 */
  // Global per-session token: undefined => not consumed; true => consumed (no more autoloads)
  if (typeof window.__paintAutoloadConsumed === 'undefined') { window.__paintAutoloadConsumed = false; }
  /* PAINT_AUTOLOAD_V4: Autoload startup image with resilient retries */
  w._autoloaded = false;
  w._tryAutoload = function(){ if (window.__paintAutoloadConsumed) return;
    if(w._autoloaded) return;
    const candidates = ['assets/startup-image.png', 'data:image/png;base64,'];
    let idx = 0;
    const attempt = ()=>{
      if(w._autoloaded || idx >= candidates.length) return;
      const src = candidates[idx++];
      try {
        if(typeof w.loadImageFrom === 'function'){
          // Use an Image probe to ensure availability, then delegate to loader
          const probe = new Image();
          probe.onload = ()=>{ w._autoloaded = true; w.loadImageFrom(src); };
          probe.onerror = ()=>{ setTimeout(attempt, 150); };
          probe.src = src;
        } else {
          setTimeout(attempt, 150);
        }
      } catch(e){ setTimeout(attempt, 150); }
    };
    attempt();
    // Retry a few times in case layout/resize clears the canvas
    let retries = 0;
    const retryTick = ()=>{
      if(w._autoloaded && typeof w._lastLoadedImageSrc === 'string'){
        // Redraw after resizes for a short warm-up window
        if(retries < 6){ setTimeout(()=>{ try { w.loadImageFrom(w._lastLoadedImageSrc); } catch(e){} }, 250); }
      } else if(retries < 10) {
        attempt();
      }
      if(retries++ < 10) setTimeout(retryTick, 300);
    };
    retryTick();
  };
  // Schedule autoload after initial mount
  try { requestAnimationFrame(()=> setTimeout(()=> w._tryAutoload(), 120)); } catch(e) { setTimeout(()=> w._tryAutoload(), 200); }

  /* PAINT_SINGLE_RUN_AUTOLOAD */
  // Ensure autoload runs only once per site load
  if(!window.__paintAutoloadDone){
    window.__paintAutoloadDone = true;
    w._autoloaded = false;
    if(typeof w._tryAutoload === 'function'){
      try { w._tryAutoload(); } catch(e) { console.error(e); }
    }
  } else {
    w._autoloaded = true; // Skip autoload on subsequent openings
  }
  // Public API: load image into canvas
  /* PAINT_STARTUP_PATCH_V3 */
  w._lastLoadedImageSrc = null;
  w.loadImageFrom = function(src){
    try {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = ()=>{
        try {
          w._lastLoadedImageSrc = src;
          // Ensure canvas has a size: if layout not ready, fall back to image size or 800x600
          let targetW = canvas.clientWidth || img.width || 800;
          let targetH = canvas.clientHeight || img.height || 600;
          // Cap extremes to avoid huge canvases
          const MAX_W = 1600, MAX_H = 1200;
          targetW = Math.min(MAX_W, Math.max(200, targetW));
          targetH = Math.min(MAX_H, Math.max(150, targetH));
          // Device pixel ratio handling
          const dpr = (window.devicePixelRatio||1);
          canvas.width = Math.floor(targetW * dpr);
          canvas.height = Math.floor(targetH * dpr);
          canvas.style.width = targetW + 'px';
          canvas.style.height = targetH + 'px';
          const ctx2 = canvas.getContext('2d');
          ctx2.setTransform(dpr,0,0,dpr,0,0);
          ctx2.clearRect(0,0,targetW,targetH);
          // Fit image preserving aspect ratio within target area
          const r = Math.min(targetW / img.width, targetH / img.height);
          const dw = Math.floor(img.width * r), dh = Math.floor(img.height * r);
          const dx = Math.floor((targetW - dw)/2), dy = Math.floor((targetH - dh)/2);
          ctx2.imageSmoothingEnabled = true;
          ctx2.drawImage(img, dx, dy, dw, dh);
        } catch(e){ console.error(e); }
      };
      img.src = src;
    } catch(e){ console.error('Paint loadImageFrom error', e); }
  };
  // Plan B autoload: try to load startup image after a short delay
  try {
    const imgPath = 'assets/startup-image.png';
    setTimeout(()=>{
      if(typeof w.loadImageFrom === 'function'){
        w.loadImageFrom(imgPath);
      } else {
        console.warn('Paint.loadImageFrom not ready for autoload');
      }
    }, 500);
  } catch(e){ console.error('Plan B autoload error', e); }

  /* PAINT_CLOSE_IMAGE_V1 */
  // Close image: clear canvas and prevent auto-redraw
  w.closeImage = function(){ window.__paintAutoloadConsumed = true;
    try {
      const ctx = canvas.getContext('2d');
      ctx.setTransform(1,0,0,1,0,0);
      ctx.clearRect(0,0,canvas.width,canvas.height);
      w._lastLoadedImageSrc = null;
      // Mark as autoloaded so startup logic won't run again on this window
      w._autoloaded = true;
    } catch(e){ console.error(e); }
  };
  // If user clicks existing Clear button, also stop image persistence
  try {
    w.el.addEventListener('click', (ev)=>{
      const t = ev.target;
      if(t && t.tagName==='BUTTON' && t.textContent && t.textContent.trim().toLowerCase()==='clear'){
        w._lastLoadedImageSrc = null;
        w._autoloaded = true;
      }
    });
  } catch(e){}

  // Mark consumed when window is closed/removed from DOM
  try {
    const mo = new MutationObserver(()=>{
      if(!document.body.contains(w.el)) { window.__paintAutoloadConsumed = true; mo.disconnect(); }
    });
    mo.observe(document.body, {childList:true, subtree:true});
  } catch(e){}
  // Inject a 'Close Image' button into the toolbar
  try {
    const tb = w.el.querySelector('.toolbar') || w.el.querySelector('[data-toolbar]') || w.el;
    const btn = document.createElement('button');
    btn.textContent = 'Close Image';
    btn.title = 'Clear canvas and stop auto-redraw';
    btn.addEventListener('click', ()=> w.closeImage());
    tb && tb.appendChild(btn);
  } catch(e){}
  return w;
});
